"""CRUD operations for users."""
from models import User


# In-memory storage (simulates a database)
_users = {}
_next_id = 1


def reset():
    """Reset the user store (for testing)."""
    global _users, _next_id
    _users = {}
    _next_id = 1


def create_user(first_name, last_name, email, phone,
                street, city, state, zip_code):
    """Create a new user and return it."""
    global _next_id
    user = User(
        user_id=_next_id,
        first_name=first_name,
        last_name=last_name,
        email=email,
        phone=phone,
        street=street,
        city=city,
        state=state,
        zip_code=zip_code,
    )
    _users[_next_id] = user
    _next_id += 1
    return user


def get_user(user_id):
    """Retrieve a user by ID."""
    return _users.get(user_id)


def update_user(user_id, **fields):
    """Update user fields. Returns the updated user or None."""
    user = _users.get(user_id)
    if user is None:
        return None
    for key, value in fields.items():
        if key == "first_name":
            user.first_name = value
        elif key == "last_name":
            user.last_name = value
        elif key == "email":
            user.email = value
        elif key == "phone":
            user.phone = value
        elif key == "street":
            user.street = value
        elif key == "city":
            user.city = value
        elif key == "state":
            user.state = value
        elif key == "zip_code":
            user.zip_code = value
    return user


def delete_user(user_id):
    """Delete a user by ID. Returns True if deleted."""
    if user_id in _users:
        del _users[user_id]
        return True
    return False


def list_users():
    """Return all users as a list."""
    return list(_users.values())


def get_users_by_state(state):
    """Return all users in a given state."""
    return [u for u in _users.values() if u.state == state]


def get_users_by_city(city):
    """Return all users in a given city."""
    return [u for u in _users.values() if u.city == city]

