"""Search service for finding users by various criteria."""
from user_service import list_users


def search_by_name(query):
    """Search users whose first or last name contains the query (case-insensitive)."""
    query_lower = query.lower()
    results = []
    for user in list_users():
        if (query_lower in user.first_name.lower() or
                query_lower in user.last_name.lower()):
            results.append(user)
    return results


def search_by_email(query):
    """Search users whose email contains the query."""
    query_lower = query.lower()
    return [u for u in list_users() if query_lower in u.email.lower()]


def search_by_location(city=None, state=None, zip_code=None):
    """Search users by location fields."""
    results = list_users()
    if city:
        results = [u for u in results if u.city.lower() == city.lower()]
    if state:
        results = [u for u in results if u.state.lower() == state.lower()]
    if zip_code:
        results = [u for u in results if u.zip_code == zip_code]
    return results


def search_advanced(first_name=None, last_name=None, city=None, state=None):
    """Advanced search combining name and location filters."""
    results = list_users()
    if first_name:
        results = [u for u in results
                    if first_name.lower() in u.first_name.lower()]
    if last_name:
        results = [u for u in results
                    if last_name.lower() in u.last_name.lower()]
    if city:
        results = [u for u in results if u.city.lower() == city.lower()]
    if state:
        results = [u for u in results if u.state.lower() == state.lower()]
    return results


def format_search_result(user):
    """Format a single search result for display."""
    return {
        "id": user.user_id,
        "name": f"{user.first_name} {user.last_name}",
        "email": user.email,
        "location": f"{user.city}, {user.state} {user.zip_code}",
    }


def format_search_results(users):
    """Format a list of search results."""
    return [format_search_result(u) for u in users]

