"""REST API endpoints for user management."""
import json
import sys
import os
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from user_service import create_user, get_user, update_user, delete_user, list_users


def handle_create_user(request_body):
    """Handle POST /users - create a new user.

    Expected JSON body:
    {
        "first_name": "John",
        "last_name": "Doe",
        "email": "john@example.com",
        "phone": "555-0100",
        "street": "123 Main St",
        "city": "Springfield",
        "state": "IL",
        "zip_code": "62701"
    }
    """
    data = json.loads(request_body)

    required = ["first_name", "last_name", "email", "phone",
                "street", "city", "state", "zip_code"]
    missing = [f for f in required if f not in data]
    if missing:
        return 400, {"error": f"Missing fields: {missing}"}

    user = create_user(
        first_name=data["first_name"],
        last_name=data["last_name"],
        email=data["email"],
        phone=data["phone"],
        street=data["street"],
        city=data["city"],
        state=data["state"],
        zip_code=data["zip_code"],
    )
    return 201, user.to_dict()


def handle_get_user(user_id):
    """Handle GET /users/:id - retrieve a user."""
    user = get_user(user_id)
    if user is None:
        return 404, {"error": "User not found"}
    return 200, user.to_dict()


def handle_update_user(user_id, request_body):
    """Handle PUT /users/:id - update a user.

    Expected JSON body with any subset of user fields:
    {
        "first_name": "Jane",
        "city": "Chicago"
    }
    """
    data = json.loads(request_body)
    user = update_user(user_id, **data)
    if user is None:
        return 404, {"error": "User not found"}
    return 200, user.to_dict()


def handle_delete_user(user_id):
    """Handle DELETE /users/:id - delete a user."""
    if delete_user(user_id):
        return 204, {}
    return 404, {"error": "User not found"}


def handle_list_users():
    """Handle GET /users - list all users."""
    users = list_users()
    return 200, [u.to_dict() for u in users]
